const fs = require('fs');

const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const dateStr = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const dateCompact = dateStr.replace(/-/g, '');

// APPROVAL_QUEUE.md 읽기
let approvalContent = '(file not found)';
try {
  approvalContent = fs.readFileSync(
    'C:/Users/pro/ObsidianVaults/VESPERA_Vault/APPROVAL_QUEUE.md',
    'utf-8'
  );
} catch(e) { approvalContent = `(read error: ${e.message})`; }

// AUDIT_LOG.md 읽기
let auditContent = '(file not found)';
try {
  auditContent = fs.readFileSync(
    'C:/Users/pro/ObsidianVaults/VESPERA_Vault/AUDIT_LOG.md',
    'utf-8'
  );
} catch(e) { auditContent = `(read error: ${e.message})`; }

// Pending 항목 추출
const pendingRows = approvalContent
  .split('\n')
  .filter(l => l.trim().startsWith('|') && l.includes('Pending'))
  .join('\n') || '(없음)';

// 최근 Audit 3줄
const auditRows = auditContent
  .split('\n')
  .filter(l => l.trim().startsWith('|') && !l.includes('---') && !l.includes('Timestamp'))
  .slice(-3)
  .join('\n') || '(없음)';

const content = [
  '---',
  'type: daily_brief',
  `date: ${dateStr}`,
  '---',
  `# Daily Brief - ${dateStr}`,
  '',
  '## Approval Queue',
  pendingRows,
  '',
  '## Recent Audit',
  auditRows,
  '',
  "## Today's Focus",
  '- [ ] ',
  ''
].join('\n');

const fileName = `${dateCompact}_daily_brief.md`;

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(content, 'utf-8'),
  fileName,
  'text/markdown'
);

return [{ json: { content, filename: fileName }, binary: { brief: binaryData } }];
